public List<int[]> mergeIntervals(List<int[]> intervalList) {
    if (intervalList.isEmpty()) return new ArrayList<>();

    // Sort intervals by start time
    intervalList.sort(Comparator.comparingInt(a -> a[0]));

    List<int[]> merged = new ArrayList<>();
    merged.add(intervalList.get(0));

    for (int i = 1; i < intervalList.size(); i++) {
        int[] current = intervalList.get(i);
        int[] last = merged.get(merged.size() - 1);

        if (current[0] <= last[1]) {
            // Merge overlapping intervals
            last[1] = Math.max(last[1], current[1]);
        } else {
            merged.add(current);
        }
    }

    return merged;
}

